/* ============================== iTunes 앨범 커버 (JSONP) ============================== */
/* JSONP: fetch()는 CORS에 막히지만 <script> 태그는 통과함 */
const albumCache = {};
let jsonpId = 0;

function itunesJsonp(query) {
  return new Promise((resolve) => {
    const cbName = `__itunes_cb_${++jsonpId}`;
    const timeout = setTimeout(() => { cleanup(); resolve(null); }, 4000);
    function cleanup() { clearTimeout(timeout); delete window[cbName]; try { document.head.removeChild(script); } catch(e){} }
    window[cbName] = (data) => { cleanup(); resolve(data); };
    const script = document.createElement("script");
    script.src = `https://itunes.apple.com/search?term=${encodeURIComponent(query)}&media=music&limit=1&callback=${cbName}`;
    script.onerror = () => { cleanup(); resolve(null); };
    document.head.appendChild(script);
  });
}

function useAlbumArt(artist, title) {
  const [url, setUrl] = useState(null);
  React.useEffect(() => {
    const key = `${artist}||${title}`;
    if (albumCache[key] !== undefined) { setUrl(albumCache[key]); return; }
    itunesJsonp(`${artist} ${title}`).then((data) => {
      const img = data?.results?.[0]?.artworkUrl100?.replace("100x100","300x300") || null;
      albumCache[key] = img;
      setUrl(img);
    });
  }, [artist, title]);
  return url;
}

/* 앨범 커버 표시 컴포넌트: 로드 전엔 그라디언트+이모지 폴백 */
function AlbumCover({ song, className = "", style = {} }) {
  const url = useAlbumArt(song.artist, song.title);
  if (url) {
    return <img src={url} alt={song.title} className={className} style={{ objectFit:"cover", ...style }} />;
  }
  return (
    <div className={`bg-gradient-to-br ${song.cover} flex items-center justify-center ${className}`} style={style}>
      <span>{song.emoji}</span>
    </div>
  );
}

