/* ===================== 화면 3: 노래 듣기 (mock player + 가사) ===================== */
function PlayerScreen({ go, ctx }) {
  const { song } = ctx;
  if (!song) return <div className="px-5 pt-10 text-center text-purple-600">노래를 선택해 주세요.</div>;
  const [playing, setPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [ttsPlaying, setTtsPlaying] = useState(false);
  const audioRef = React.useRef(null);
  const sit = SITUATIONS.find((s) => s.id === song.situation);

  // 음원 파일 재생/일시정지
  React.useEffect(() => {
    if (!song.audioFile) return;
    if (!audioRef.current) {
      audioRef.current = new Audio(song.audioFile);
      audioRef.current.addEventListener("timeupdate", () => {
        const a = audioRef.current;
        if (a && a.duration) setProgress((a.currentTime / a.duration) * 100);
      });
      audioRef.current.addEventListener("ended", () => { setPlaying(false); setProgress(0); });
    }
    if (playing) audioRef.current.play();
    else audioRef.current.pause();
    return () => {};
  }, [playing, song.audioFile]);

  React.useEffect(() => {
    return () => { if (audioRef.current) { audioRef.current.pause(); audioRef.current = null; } window.speechSynthesis.cancel(); };
  }, [song.id]);

  // 화면 이동 시 TTS 정리
  React.useEffect(() => () => { window.speechSynthesis.cancel(); }, []);

  // 문장 듣기: 가사 줄 TTS (자연스러운 한국어 음성)
  function pickBestKoreanVoice() {
    const voices = window.speechSynthesis.getVoices();
    const ko = voices.filter((v) => v.lang.startsWith("ko"));
    // 우선순위: Google 한국의 > InJoon/Heami > Yuna > 기본 ko
    const priority = ["Google", "InJoon", "Heami", "Yuna", "SunHi"];
    for (const name of priority) {
      const found = ko.find((v) => v.name.includes(name));
      if (found) return found;
    }
    return ko[0] || null;
  }

  function speakLine(text, voice, rate, onEnd) {
    const utt = new SpeechSynthesisUtterance(text);
    utt.lang = "ko-KR";
    utt.rate = rate;
    utt.pitch = 1.0;
    if (voice) utt.voice = voice;
    utt.onend = onEnd;
    utt.onerror = onEnd;
    window.speechSynthesis.speak(utt);
  }

  function handleSentenceTTS() {
    if (!song.lyricLines || song.lyricLines.length === 0) return;
    if (ttsPlaying) { window.speechSynthesis.cancel(); setTtsPlaying(false); return; }

    const voice = pickBestKoreanVoice();
    const lines = song.lyricLines.filter((l) => l.trim());
    setTtsPlaying(true);
    window.speechSynthesis.cancel();

    // 줄 단위로 끊어서 자연스럽게 읽기
    let idx = 0;
    const readNext = () => {
      if (idx >= lines.length) { setTtsPlaying(false); return; }
      speakLine(lines[idx], voice, 0.95, () => {
        idx++;
        // 줄 사이에 짧은 쉼
        setTimeout(readNext, 250);
      });
    };
    readNext();
  }

  // 음성 목록 로드 (브라우저가 비동기로 음성을 로드함)
  React.useEffect(() => {
    if (typeof window === "undefined") return;
    window.speechSynthesis.getVoices();
    window.speechSynthesis.onvoiceschanged = () => window.speechSynthesis.getVoices();
  }, []);

  // 구간 듣기: YouTube 해당 시점부터 열기
  function handleSegmentYouTube() {
    if (!song.youtubeId) return;
    const t = song.lyricStart || 0;
    window.open(`https://www.youtube.com/watch?v=${song.youtubeId}&t=${t}`, "_blank");
  }

  const sameSituation = SONGS.filter((s) => s.situation === song.situation);
  const nextSong = sameSituation[(sameSituation.findIndex((s) => s.id === song.id) + 1) % sameSituation.length];

  return (
    <div className="px-5 pt-3 pb-24">
      <Header title={`${sit?.name} 학습 ${sit?.icon}`} onBack={() => ctx.from === "todays" ? go("todays") : go("songList", { situation: song.situation, artist: null })} />
      <div className="text-center mt-2 mb-3">
        <Pill className="bg-pink-100 text-pink-500">선택한 상황: {sit?.name}</Pill>
        <p className="tt11 text-purple-600 mt-2">노래를 듣고 노래 가사의 상황과 메시지를 생각해 보세요</p>
      </div>
      <AlbumCover song={song} className="mx-auto w-52 h-52 rounded-3xl shadow-lg text-6xl" />
      <div className="text-center mt-3">
        <div className="text-lg font-black text-purple-700">{song.title}</div>
        <div className="text-xs text-purple-600">{song.artist}</div>
      </div>

      {/* 가사 박스 + 듣기 버튼 */}
      {song.lyricLines && song.lyricLines.length > 0 && (
        <div className="mt-3 rounded-2xl lyricbox p-4 text-center text-sm leading-7">
          {song.lyricLines.map((l, i) => (
            <div key={i} className={l.replace(/\s/g,"").includes("손을잡") ? "font-black text-pink-300 text-base" : ""}>
              {l}
            </div>
          ))}
          {/* 듣기 버튼 행 */}
          <div className="flex gap-2 mt-3 justify-center">
            {song.audioFile && (
              <button onClick={() => {
                const audio = new Audio(song.audioFile);
                audio.currentTime = song.lyricStart || 0;
                audio.play();
                setTimeout(() => audio.pause(), 20000);
              }}
                className="flex items-center gap-1.5 rounded-full px-4 py-1.5 bg-red-500 text-white tt12 font-bold active:scale-95 shadow">
                ▶ 구간 듣기
              </button>
            )}
            {!song.audioFile && song.youtubeId && (
              <button onClick={handleSegmentYouTube}
                className="flex items-center gap-1.5 rounded-full px-4 py-1.5 bg-red-500 text-white tt12 font-bold active:scale-95 shadow">
                ▶ 구간 듣기
              </button>
            )}
            {song.lyricLines.length > 0 && (
              <button onClick={handleSentenceTTS}
                className={`flex items-center gap-1.5 rounded-full px-4 py-1.5 tt12 font-bold active:scale-95 shadow
                  ${ttsPlaying ? "bg-pink-400 text-white" : "bg-white/20 text-white border border-white/40"}`}>
                {ttsPlaying ? "⏹ 중지" : "🔊 문장 듣기"}
              </button>
            )}
          </div>
          {song.audioFile && (
            <p className="tt10 text-white/50 mt-2">가사 시점부터 20초간 재생됩니다</p>
          )}
          {!song.audioFile && song.youtubeId && (
            <p className="tt10 text-white/50 mt-2">구간 듣기는 YouTube에서 해당 가사 시점({Math.floor((song.lyricStart||0)/60)}분 {(song.lyricStart||0)%60}초)부터 재생됩니다</p>
          )}
        </div>
      )}

      <div className="mt-3 px-2">
        <div className="h-1.5 rounded-full bg-purple-100 overflow-hidden">
          <div className="h-full bg-pink-400 transition-all" style={{ width: `${progress}%` }} />
        </div>
        <div className="flex justify-between tt10 text-purple-500 mt-1">
          <span>0:{String(Math.floor(progress * 2.2)).padStart(2, "0")}</span>
          <span>03:46</span>
        </div>
      </div>
      <div className="flex items-center justify-center mt-3">
        <button onClick={() => song.audioFile && setPlaying((p) => !p)}
          disabled={!song.audioFile}
          className={`flex items-center gap-1.5 rounded-full px-4 py-1.5 text-white tt12 font-bold active:scale-95 shadow ${song.audioFile ? "bg-purple-500" : "bg-purple-200 cursor-not-allowed"}`}>
          {playing ? "⏸ 일시정지" : "▶ 전체 듣기"}
        </button>
      </div>
      {!song.audioFile && (
        <p className="text-center tt10 text-purple-500 mt-2">음원 준비 중</p>
      )}
      <div className="flex gap-2 mt-3">
        <button onClick={() => go("player", { song: nextSong })}
          className="flex-1 rounded-full py-2 text-xs font-bold bg-purple-100 text-purple-600 active:scale-95">다른 노래 보기 🎵</button>
        <button onClick={() => go("collocation", { song, idx: 0 })}
          className="flex-1 rounded-full py-2 text-xs font-bold bg-pink-400 text-white active:scale-95">연어 학습하기 →</button>
      </div>

      <div className="mt-4 mb-2">
        <button onClick={() => ctx.from === "todays" ? go("todays") : go("songList", { situation: song.situation, artist: null })}
          className="w-9 h-9 rounded-full bg-purple-100 text-purple-500 flex items-center justify-center active:scale-90 shadow-sm">
          ←
        </button>
      </div>
    </div>
  );
}

