function CollocationScreen({ go, ctx, bookmarks, toggleBookmark }) {
  const { song, idx } = ctx;
  const c = song.collocations[idx];
  if (!c) return <div className="px-5 pt-3 pb-24"><Header title="연어 학습 💗" onBack={() => go("player", { song })} /><p className="text-purple-600 text-center mt-4">이 노래에 등록된 연어가 없습니다.</p></div>;
  const full = COLLOCATIONS.find((x) => x.expression === c.word) || {};
  const hasNext = song.collocations.length > 1;
  const nextIdx = (idx + 1) % song.collocations.length;
  const marked = bookmarks.includes(c.id);

  return (
    <div className="px-5 pt-3 pb-24">
      <Header title="연어 학습 💗" onBack={() => go("songList", { situation: song.situation, artist: null })} />
      <p className="text-center tt11 text-purple-600 mb-2">노래 속 표현 배우기</p>

      <div className="rounded-2xl glass85 shadow p-3">
        <div className="flex items-center gap-3">
          <AlbumCover song={song} className="w-14 h-14 rounded-xl text-2xl" />
          <div className="flex-1">
            <div className="tt10 text-purple-600">{song.title} · {song.artist}</div>
            <Pill className="bg-pink-100 text-pink-500 mt-1">오늘의 연어</Pill>
            <div className="text-2xl font-black text-pink-500 leading-tight">{c.word}</div>

          </div>
          <button onClick={() => toggleBookmark(c.id)}
            className={`flex flex-col items-center gap-0.5 active:scale-90 transition`}>
            <span className="text-2xl">{marked ? "🔖" : "🏷️"}</span>
            <span className="tt10">{marked ? "저장됨" : "저장"}</span>
          </button>
        </div>

        <div className="mt-3">
          <Row icon="💡" label="의미">{full.meaning || c.meaning}</Row>
          <Row icon="💗" label="상황">{full.situation}</Row>
          <Row icon="🎧" label="듣는 사람">{full.listener}</Row>
          <Row icon="🙂" label="말하는 사람">{full.attitude}</Row>
        </div>
      </div>

      <div className="flex gap-2 mt-4">
        {hasNext && (
          <button onClick={() => go("collocation", { song, idx: nextIdx })}
            className="flex-1 rounded-full py-2 text-xs font-bold bg-purple-100 text-purple-600 active:scale-95">다른 연어 보기</button>
        )}
      </div>

      <div className="mt-4 mb-2">
        <button onClick={() => go("songList", { situation: song.situation, artist: null })}
          className="w-9 h-9 rounded-full bg-purple-100 text-purple-500 flex items-center justify-center active:scale-90 shadow-sm">
          ←
        </button>
      </div>
    </div>
  );
}

/* =============== 화면 4.5: 연어 심화 (HTML MVP 강점 재구현) =============== */
function LearnMoreScreen({ go, ctx }) {
  const { song, collocation: c } = ctx;
  const d = c.deep || {};
  const [picked, setPicked] = useState(null); // 퀴즈 선택 인덱스
  const [quizAttempts, setQuizAttempts] = useState(0);
  const [quizPhase, setQuizPhase] = useState("solving"); // solving | firstWrong | revealed

  return (
    <div className="px-5 pt-3 pb-24">
      <Header title="관련 연어 더 보기" onBack={() => go("collocation", { song, idx: song.collocations.indexOf(c) })} />
      <div className="text-center mt-1">
        <Pill className="bg-pink-100 text-pink-500 text-sm">{c.word}</Pill>
        <p className="tt11 text-purple-600 mt-1">그림 · 다른 노래 · 상황별 의미로 더 배워요</p>
      </div>

      {/* ① 그림으로 이해하기 */}
      {d.comic && (
        <>
          <SectionTitle>그림으로 이해하기</SectionTitle>
          <div className="grid grid-cols-2 gap-3">
            <div className="rounded-2xl overflow-hidden shadow">
              <img src={IMG_SONJABDA_2} alt="연인이 손을 잡고 걷는 모습" className="w-full h-32 object-cover" />
              <p className="tt11 text-purple-600 text-center py-2 px-2 leading-snug">파트너와 협력의 손을 잡아요</p>
            </div>
            <div className="rounded-2xl overflow-hidden shadow">
              <img src={IMG_SONJABDA_1} alt="비즈니스 파트너가 악수하는 모습" className="w-full h-32 object-cover" />
              <p className="tt11 text-purple-600 text-center py-2 px-2 leading-snug">사랑하는 사람과 손을 잡아요</p>
            </div>
          </div>
        </>
      )}

      {/* ③ 관련 연어 */}
      {c.similar && (
        <>
          <SectionTitle note="유사 · 대비">관련 연어</SectionTitle>
          <div className="space-y-2">
            {c.similar.map((s, i) => (
              <div key={i} className="rounded-xl glass80 shadow p-3">
                <div className="tt12 font-bold text-purple-700">{s.word}</div>
                <div className="tt10 text-purple-600">{s.note}</div>
              </div>
            ))}
          </div>
        </>
      )}

      {/* ④ 상황에 따라 달라지는 의미 (연구 핵심) */}
      {d.variations && (
        <>
          <SectionTitle note="8개 상황(장) 안에서">상황에 따라 달라지는 의미</SectionTitle>
          <div className="rounded-2xl glass85 shadow overflow-hidden">
            {d.variations.map((v, i) => {
              const sit = SITUATIONS.find((s) => s.name === v.sit);
              return (
                <div key={i} className="flex items-center gap-2 p-3 border-b border-purple-50 last:border-0">
                  <div className={`w-20 h-9 shrink-0 rounded-full bg-gradient-to-br ${sit?.grad || "from-purple-200 to-pink-200"} text-white tt10 font-bold flex items-center justify-center text-center px-1 leading-tight`}>
                    {v.sit}
                  </div>
                  <div className="flex-1 tt12 text-purple-800 leading-snug">{v.meaning}</div>
                </div>
              );
            })}
          </div>
          <p className="tt10 text-purple-500 mt-2 px-1">
            동일한 연어가 사용역의 <b>장(field)</b>에 따라 담화 기능을 달리하는 양상입니다.
          </p>
        </>
      )}

      {/* ⑤ 간단한 퀴즈 (2단계 피드백: 1차 오답→힌트+재시도, 2차 오답→정답 공개) */}
      {d.quiz && (
        <>
          <SectionTitle note="1문항">간단한 문제</SectionTitle>
          <div className="rounded-2xl glass85 shadow p-4">
            <p className="tt13 font-bold text-purple-700 mb-3">{d.quiz.q}</p>
            <div className="space-y-2">
              {d.quiz.choices.map((ch, i) => {
                let cls = "border-purple-100 bg-white text-purple-700";
                if (quizPhase === "revealed") {
                  if (ch.correct) cls = "border-emerald-300 bg-emerald-50 text-emerald-600";
                  else if (i === picked) cls = "border-rose-300 bg-rose-50 text-rose-500";
                  else cls = "border-purple-50 bg-white text-purple-300";
                } else if (i === picked && quizPhase === "firstWrong") {
                  cls = "border-rose-300 bg-rose-50 text-rose-500";
                }
                return (
                  <button key={i}
                    disabled={quizPhase === "revealed" || quizPhase === "firstWrong"}
                    onClick={() => {
                      setPicked(i);
                      if (ch.correct) {
                        playSound("correct");
                        setQuizPhase("revealed");
                      } else {
                        playSound("wrong");
                        const n = quizAttempts + 1;
                        setQuizAttempts(n);
                        if (n >= 2) {
                          setQuizPhase("revealed");
                        } else {
                          setQuizPhase("firstWrong");
                        }
                      }
                    }}
                    className={`w-full text-left rounded-xl border px-3 py-2.5 tt13 font-bold transition ${cls}`}>
                    {ch.text}
                    {quizPhase === "revealed" && ch.correct ? "  ✅" : ""}
                    {quizPhase === "revealed" && i === picked && !ch.correct ? "  ✕" : ""}
                  </button>
                );
              })}
            </div>

            {/* 1차 오답: 힌트만, 정답 비공개 */}
            {quizPhase === "firstWrong" && (
              <div className="mt-3 space-y-2">
                <div className="rounded-xl bg-amber-50 p-2 tt11 text-amber-700">
                  다시 한번 더 생각해 보세요. 💡
                </div>
                <button onClick={() => { setPicked(null); setQuizPhase("solving"); }}
                  className="w-full rounded-full py-2 tt11 font-bold bg-purple-100 text-purple-600 active:scale-95">
                  다시 풀기
                </button>
              </div>
            )}

            {/* 정답 또는 2차 오답: 해설 공개 */}
            {quizPhase === "revealed" && (
              <div className="mt-3 rounded-xl bg-purple-50 p-2 tt11 text-purple-600">
                {d.quiz.choices[picked]?.correct ? "정답이에요! 🎉 " : "정답을 함께 확인해요. "}
                {d.quiz.explain}
              </div>
            )}
          </div>
        </>
      )}

      <button onClick={() => go("activity", { song, collocation: c })}
        className="w-full mt-5 rounded-full py-2.5 text-sm font-black bg-gradient-to-r from-purple-400 to-pink-400 text-white shadow active:scale-95">
        연습하러 가기 →
      </button>

      <div className="mt-4 mb-2">
        <button onClick={() => go("collocation", { song, idx: song.collocations.indexOf(c) })}
          className="w-9 h-9 rounded-full bg-purple-100 text-purple-500 flex items-center justify-center active:scale-90 shadow-sm">
          ←
        </button>
      </div>
    </div>
  );
}

/* ===================== 화면 5: 마무리 활동 + AI 피드백 ===================== */
function ActivityScreen({ go, ctx, saveRecord }) {
  const { song, collocation: c } = ctx;
  const sit = SITUATIONS.find((s) => s.id === song.situation);
  const [text, setText] = useState("");
  const [loading, setLoading] = useState(false);
  const [feedback, setFeedback] = useState(null);
  const [error, setError] = useState("");

  async function checkAI() {
    if (!text.trim()) { setError("가사를 먼저 작성해 주세요."); return; }
    setError(""); setLoading(true); setFeedback(null);
    const prompt = `당신은 한국어 학습자의 작문을 평가하는 친절한 한국어 교사입니다.
학습자는 K-POP 가사 학습 앱에서 목표 연어를 사용해 2~4줄의 짧은 가사를 작성했습니다.

[목표 연어] ${c.word}
[연어 의미] ${c.meaning}
[학습 상황(장)] ${sit?.name} — ${c.situation}
[학습자 작문]
${text}

아래 5개 항목을 평가하여 반드시 JSON으로만 응답하세요. 마크다운/설명/코드펜스 없이 JSON 객체만 출력합니다.
{
  "uses_target": true 또는 false (목표 연어를 적절히 사용했는가),
  "meaning_ok": "의미 적절성에 대한 한 문장 평가",
  "context_ok": "상황 맥락 적합성에 대한 한 문장 평가",
  "suggestion": "더 자연스러운 표현 제안 한 문장",
  "revision": "학습자 작문을 살짝 다듬은 2~4줄 수정 예시"
}`;
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: 1000,
          messages: [{ role: "user", content: prompt }],
        }),
      });
      const data = await res.json();
      const raw = data.content.map((i) => (i.type === "text" ? i.text : "")).join("");
      const clean = raw.replace(/```json|```/g, "").trim();
      setFeedback(JSON.parse(clean));
    } catch (e) {
      setError("AI 점검 중 문제가 발생했습니다. 잠시 후 다시 시도해 주세요.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="px-5 pt-3 pb-24">
      <Header title="마무리 활동 🎶" onBack={() => go("learnMore", { song, collocation: c })} />
      <p className="text-center tt11 text-purple-600 mb-2">목표 연어를 활용해 나만의 가사를 만들고 AI 점검을 받아 보세요</p>

      <div className="rounded-2xl glass85 shadow p-3 flex items-center gap-2">
        <AlbumCover song={song} className="w-10 h-10 rounded-lg text-lg" />
        <div className="flex-1 tt11 text-purple-500">목표 연어</div>
        <Pill className="bg-pink-100 text-pink-500 text-sm">{c.word}</Pill>
        <Pill className="bg-purple-100 text-purple-500">상황: {sit?.name}</Pill>
      </div>

      <div className="mt-3">
        <label className="text-xs font-bold text-purple-600">✏️ 가사 작성 (2~4줄)</label>
        <textarea value={text} onChange={(e) => setText(e.target.value)} rows={4} maxLength={300}
          placeholder={`예) 어두운 밤에도 네 ${c.word.split(" ")[0]}...`}
          className="w-full mt-1 rounded-2xl border border-purple-200 glass80 p-3 text-sm text-purple-800 outline-none focus:border-pink-300" />
        <div className="text-right tt10 text-purple-500">{text.length}/300</div>
      </div>

      {error && <div className="tt11 text-rose-500 text-left mb-2">{error}</div>}

      <button onClick={checkAI} disabled={loading}
        className="w-full rounded-full py-2.5 text-sm font-black bg-gradient-to-r from-purple-400 to-pink-400 text-white shadow active:scale-95 disabled:opacity-60">
        {loading ? "AI가 점검 중…" : "🤖 AI 오류 점검 받기"}
      </button>

      {feedback && (
        <div className="mt-4 rounded-2xl glass90 shadow p-3 space-y-2">
          <div className="text-xs font-black text-purple-700">🤖 AI 점검 결과</div>
          <FB ok={feedback.uses_target} label="목표 연어 사용">
            {feedback.uses_target ? `목표 연어 '${c.word}'를 적절히 사용했습니다.` : `목표 연어 '${c.word}'가 사용되지 않았어요.`}
          </FB>
          <FB ok label="의미 적절성">{feedback.meaning_ok}</FB>
          <FB ok label="상황 맥락">{feedback.context_ok}</FB>
          <FB ok label="자연스러운 표현">{feedback.suggestion}</FB>
          <div className="rounded-xl bg-purple-50 p-2">
            <div className="tt11 font-bold text-purple-600 mb-1">✍️ 수정 예시</div>
            <div className="tt12 text-purple-800 whitespace-pre-line">{feedback.revision}</div>
          </div>
          <div className="flex gap-2 pt-1">
            <button onClick={() => { setText(""); setFeedback(null); }}
              className="flex-1 rounded-full py-2 tt11 font-bold bg-purple-100 text-purple-600 active:scale-95">다시 쓰기</button>
            <button onClick={() => { saveRecord({ word: c.word, song: song.title, text }); go("history"); }}
              className="flex-1 rounded-full py-2 tt11 font-bold bg-pink-400 text-white active:scale-95">💾 최종 저장</button>
          </div>
        </div>
      )}

      <div className="mt-4 mb-2">
        <button onClick={() => go("learnMore", { song, collocation: c })}
          className="w-9 h-9 rounded-full bg-purple-100 text-purple-500 flex items-center justify-center active:scale-90 shadow-sm">
          ←
        </button>
      </div>
    </div>
  );
}

function FB({ ok, label, children }) {
  return (
    <div className="flex gap-2 tt12">
      <span>{ok ? "✅" : "⚠️"}</span>
      <div><b className="text-purple-600">{label}</b> · <span className="text-purple-800">{children}</span></div>
    </div>
  );
}

/* ===================== 보조 화면들 ===================== */
/* 날짜를 시드로 한 무작위 선택 (같은 날엔 동일, 날짜가 바뀌면 무작위 변경) */
function dailyRandom(arr) {
  const d = new Date();
  const seed = d.getFullYear() * 10000 + (d.getMonth() + 1) * 100 + d.getDate();
  const r = Math.abs(Math.sin(seed) * 10000) % 1; // 0~1
  return arr[Math.floor(r * arr.length)];
}

function TodaysScreen({ go }) {
  const all = SONGS.flatMap((s) => s.collocations.map((c) => ({ c, s })));

  // 발표 모드: 발표용 예시 고정 / 운영 모드: 날짜 기반 무작위
  let pick, badge;
  if (PRESENTATION_MODE) {
    const fs = SONGS.find((s) => s.id === FEATURED.songId) || SONGS[0];
    pick = { s: fs, c: fs.collocations[FEATURED.colIdx] };
    badge = "추천 학습 · 발표용 예시";
  } else {
    pick = dailyRandom(all);
    badge = "오늘의 추천 (매일 변경)";
  }

  // 오늘의 연어가 가사에 등장하는 곡 리스트 (lyricLines에 연어 단어 포함된 곡)
  if (!pick || !pick.c) return <div className="px-5 pt-3 pb-24"><p className="text-center text-purple-600">연어 데이터를 불러오는 중…</p></div>;
  const word = pick.c.word; // 예: "손을 잡다"
  // "손을 잡다" → "손을 잡" 처럼 핵심 어근으로 검색
  const stem = word.replace(/[다아어]$/, "").replace(/\s+/g, "");
  const relatedSongs = SONGS.filter((s) =>
    s.id !== pick.s.id &&
    s.lyricLines.some((l) => l.replace(/\s/g, "").includes(stem))
  );

  const sit = (s) => SITUATIONS.find((x) => x.id === s.situation);

  return (
    <div className="px-5 pt-3 pb-24">
      <Header title="오늘의 연어 🎶" onBack={() => go("home")} />

      {/* 연어 표시 */}
      <div className="text-center mt-4">
        <div className="text-4xl font-black text-purple-700">{pick.c.word}</div>
        <div className="tt11 text-purple-600 mt-2">{pick.c.meaning}</div>
        <div className="tt11 text-purple-600 mt-3">노래를 눌러 가사를 확인해 보세요 👆</div>
      </div>

      {/* 노래 · 단어 표 */}
      {(() => {
        const allRelated = [pick.s, ...relatedSongs];
        const wordMap = {
          "seventeen-ready-to-love": "동행",
          "treasure------i-love-you": "붙잡기",
          "bts-my-universe": "연결",
          "seventeen-damage": "신뢰",
          "bts-life-goes-on": "위로",
          "red-velvet-feel-my-rhythm": "초대",
          "bts-take-two": "재회",
        };
        return allRelated.length > 0 && (
          <div className="mt-4 rounded-2xl glass85 shadow overflow-hidden">
            <div className="flex items-center bg-purple-100 px-4 py-2">
              <div className="flex-1 tt11 font-black text-purple-600">노래</div>
              <div className="w-20 text-center tt11 font-black text-purple-600">상황</div>
              <div className="w-16 text-right tt11 font-black text-purple-600">의미</div>
            </div>
            {allRelated.map((s, i) => {
              const situation = sit(s);
              return (
                <button key={s.id} onClick={() => go("player", { song: s, from: "todays" })}
                  className={`group w-full flex items-center px-4 py-3 text-left active:bg-purple-50 transition hover:bg-purple-50 ${i < allRelated.length - 1 ? "border-b border-purple-50" : ""}`}>
                  <div className="flex-1 relative min-w-0">
                    <div className="tt12 font-bold text-purple-700">
                      {s.title}
                      <span className="song-click-hint ml-1 tt10 text-pink-400 font-normal">click</span>
                    </div>
                    <div className="tt10 text-purple-600">{s.artist}</div>
                  </div>
                  <div className="w-20 text-center">
                    <span className="tt10 text-purple-500">{situation?.name}</span>
                  </div>
                  <div className="w-16 text-right">
                    <span className="tt12 font-bold text-pink-500">{wordMap[s.id] || ""}</span>
                  </div>
                </button>
              );
            })}
          </div>
        );
      })()}

      {/* 하단 뒤로가기 */}
      <div className="mt-4 mb-2">
        <button onClick={() => go("home")}
          className="w-9 h-9 rounded-full bg-purple-100 text-purple-500 flex items-center justify-center active:scale-90 shadow-sm">
          ←
        </button>
      </div>
    </div>
  );
}

