function BookmarkScreen({ go, bookmarks, toggleBookmark, learnStatus, setLearnStatus }) {
  const marked = SONGS.flatMap((s) => s.collocations.map((c) => ({ c, s }))).filter((x) => bookmarks.includes(x.c.id));

  const STATUS = [
    { id: "new",      label: "처음 봄",    color: "bg-red-100 text-red-500",    dot: "🔴" },
    { id: "learning", label: "외우는 중",  color: "bg-yellow-100 text-yellow-600", dot: "🟡" },
    { id: "done",     label: "완료",       color: "bg-emerald-100 text-emerald-600", dot: "🟢" },
  ];

  function nextStatus(colId) {
    const cur = learnStatus[colId] || "new";
    const idx = STATUS.findIndex((s) => s.id === cur);
    const next = STATUS[(idx + 1) % STATUS.length].id;
    setLearnStatus((prev) => ({ ...prev, [colId]: next }));
  }

  return (
    <div className="px-5 pt-3 pb-24">
      <Header title="내 연어 사전 🔖" onBack={() => go("home")} />
      {marked.length === 0 ? (
        <div className="text-center mt-16">
          <div className="text-4xl mb-3">📖</div>
          <p className="text-sm font-bold text-purple-500">아직 저장된 연어가 없어요</p>
          <p className="tt11 text-purple-500 mt-1">연어 카드에서 🏷️를 눌러 저장해 보세요</p>
        </div>
      ) : (
        <>
          <div className="flex items-center justify-between mt-3 mb-2">
            <span className="tt11 text-purple-600">총 {marked.length}개 저장됨</span>
            <div className="flex gap-2 tt10 text-purple-500">
              {STATUS.map((s) => (
                <span key={s.id}>{s.dot} {marked.filter((x) => (learnStatus[x.c.id] || "new") === s.id).length}</span>
              ))}
            </div>
          </div>
          <div className="space-y-2">
            {marked.map(({ c, s }) => {
              const status = STATUS.find((x) => x.id === (learnStatus[c.id] || "new"));
              return (
                <div key={c.id} className="rounded-2xl glass80 shadow overflow-hidden">
                  <button onClick={() => go("collocation", { song: s, idx: s.collocations.indexOf(c) })}
                    className="w-full text-left p-3 active:bg-purple-50">
                    <div className="flex items-start justify-between gap-2">
                      <div className="flex-1">
                        <div className="text-base font-black text-pink-500">{c.word}</div>
                        <div className="tt11 text-purple-600 mt-0.5">{c.meaning}</div>
                        <div className="tt10 text-purple-600 mt-1">{s.title} · {s.artist}</div>
                      </div>
                      <button onClick={(e) => { e.stopPropagation(); toggleBookmark(c.id); }}
                        className="text-pink-400 text-lg shrink-0">🔖</button>
                    </div>
                  </button>
                  {/* 학습 상태 */}
                  <div className="flex items-center gap-2 px-3 pb-3">
                    <span className="tt10 text-purple-600">학습 상태:</span>
                    <button onClick={() => nextStatus(c.id)}
                      className={`rounded-full px-3 py-0.5 tt10 font-bold ${status.color} active:scale-95`}>
                      {status.dot} {status.label}
                    </button>
                    <span className="tt10 text-purple-500">← 눌러서 변경</span>
                  </div>
                </div>
              );
            })}
          </div>
        </>
      )}

      <div className="mt-4 mb-2">
        <button onClick={() => go("home")}
          className="w-9 h-9 rounded-full bg-purple-100 text-purple-500 flex items-center justify-center active:scale-90 shadow-sm">
          ←
        </button>
      </div>
    </div>
  );
}

