/* ============================================================
   ◆ 정규화 데이터 스키마 (Normalized Schema v1.0)
   ============================================================
   설계 원칙:
   ① 8영역(songDomain)은 연어 분류가 아니라 *출현곡의 주제 분류*
   ② expressionType은 내부 전용 — 학습자 화면에 직접 노출하지 않음
   ③ 핵심 표현은 실제 노래에서 확인된 표현만 사용
   ④ 노래에 직접 없는 표현은 extended(확장 표현)로만 관리
   ============================================================ */

/* ── (1) ExpressionItem: 표현 엔티티 ─────────────────────── */
const _etMap = { "협의적 연어": "strict_collocation", "연어적 표현": "broad_collocation", "관용적 표현": "idiom", "관용적·은유적 표현": "idiom", "은유적 표현": "metaphor" };
const EXPRESSION_ITEMS = COLLOCATIONS.map(function(c) {
  return {
    expressionId: "expr_" + String(c.id).padStart(3, "0"),
    expression: c.expression,
    expressionType: _etMap[c.expressionType] || "broad_collocation",
    discourseFunction: c.discourseFunction || [],
    meaning: c.meaning || "",
    similarExpressions: (c.similar || []).map(function(s) { return s.expr; }),
    contrastExpressions: (c.contrast || []).map(function(s) { return s.expr; }),
    status: c.status || (c.sourceSongs && c.sourceSongs.length > 0 ? "attested" : "extended"),
  };
});

/* ── (2) SongItem: 곡 엔티티 ─────────────────────────────── */
const _sitMap = { love: "사랑·설렘", parting: "이별·상실", comfort: "고민·불안·위로", growth: "성장", freedom: "저항·해방·사회도전", daily: "일상·청춘", world: "세계관", hope: "희망·소원" };
const SONG_ITEMS = SONGS.filter(function(s) { return s.artist && s.title; }).map(function(s, i) {
  return {
    songId: s.id || ("song_" + String(i + 1).padStart(3, "0")),
    artist: s.artist,
    title: s.title,
    songDomain: [_sitMap[s.situation] || "일상·청춘"],
    lyricKeywords: (s.lyricLines || []).slice(0, 3),
    notes: s.mood || "",
  };
});

/* ── (3) SongExpressionLink: 곡↔표현 연결 (M:N) ─────────── */
const SONG_EXPRESSION_LINKS = [];
COLLOCATIONS.forEach(function(c) {
  var exprId = "expr_" + String(c.id).padStart(3, "0");
  (c.sourceSongs || []).forEach(function(src, idx) {
    var artist = typeof src === "string" ? src.split(" - ")[0] : src.artist;
    var title  = typeof src === "string" ? src.split(" - ").slice(1).join(" - ") : src.title;
    var matched = SONGS.find(function(s) { return s.artist === artist && s.title === title; });
    SONG_EXPRESSION_LINKS.push({
      songId: matched ? matched.id : ("unregistered_" + artist + "_" + title).replace(/\s+/g, "_"),
      expressionId: exprId,
      surfaceForm: c.expression,
      evidenceType: c.evidenceType || "direct",
      isCoreForSong: idx === 0,
    });
  });
});

/* ── (4) QuestionItem: QUESTION_BANK 정의 후 지연 산출 (아래 참조) ── */
let QUESTION_ITEMS = [];

/* ── 헬퍼: 표현 → 출현곡 songDomain 동적 산출 ───────────── */
function getDomainsForExpression(exprId) {
  var linkedSongIds = SONG_EXPRESSION_LINKS
    .filter(function(l) { return l.expressionId === exprId; })
    .map(function(l) { return l.songId; });
  var domains = {};
  linkedSongIds.forEach(function(sid) {
    var song = SONG_ITEMS.find(function(s) { return s.songId === sid; });
    if (song) song.songDomain.forEach(function(d) { domains[d] = true; });
  });
  return Object.keys(domains);
}

