/* 학습자 입력과 예시(hint) 유사도 검사: 예시를 베끼거나 거의 같은 내용을 쓰면 true 반환 */
function isTooSimilarToHint(learnerText, hint) {
  if (!hint) return false;
  // "예) " 접두어 제거, 줄바꿈→공백, 공백·구두점 정리
  const clean = (s) => s.replace(/^예\)\s*/,"").replace(/\\n/g," ").replace(/[\s,.!?~…·""'']+/g,"").toLowerCase();
  const a = clean(learnerText);
  const h = clean(hint);
  if (!a || !h) return false;
  // 짧은 쪽 기준 공통 부분문자열 비율 확인
  const shorter = a.length < h.length ? a : h;
  const longer  = a.length < h.length ? h : a;
  let matchLen = 0;
  // 길이 4 이상 연속 일치 부분을 누적
  for (let len = shorter.length; len >= 4; len--) {
    for (let start = 0; start <= shorter.length - len; start++) {
      const sub = shorter.substring(start, start + len);
      if (longer.includes(sub)) { matchLen += len; break; }
    }
    if (matchLen > 0) break;
  }
  const ratio = matchLen / shorter.length;
  return ratio > 0.55;
}

/* ---------------------------- AI 호출 공통 함수 ----------------------------
   Claude API 를 호출하여 JSON 응답을 파싱한다. 실패 시 호출부에서 템플릿으로 대체한다. */
async function callClaudeJSON(prompt) {
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      max_tokens: 1000,
      messages: [{ role: "user", content: prompt }],
    }),
  });
  const data = await res.json();
  const raw = (data.content || []).map((i) => (i.type === "text" ? i.text : "")).join("");
  const clean = raw.replace(/```json|```/g, "").trim();
  return JSON.parse(clean);
}

/* §9 AI 채점 프롬프트(문장·가사 공용): 5개 기준 평가 후 JSON 반환 */
function buildGradePrompt({ task, situation, required, learnerText }) {
  return `너는 한국어교육 전문가이다. 학습자가 K-POP 연어를 사용하여 만든 ${task}을(를) 평가한다.
평가 목적은 단순 문법 교정이 아니라, 학습자가 연어로 상황에 맞는 발화를 만들고 문장과 문장의 의미적 연결성(담화 응집성)을 높였는지 확인하는 것이다.

[상황] ${situation}
[사용하도록 제시한 연어] ${required && required.length ? required.join(", ") : "(자유 선택)"}
[학습자 산출물]
${learnerText}

다음 5개 기준으로 평가하라: 1) 연어 사용 정확성 2) 상황 적절성 3) 구어 담화 자연성 4) 담화 응집성 5) 표현 확장성.
주의: 학습자 표현을 지나치게 어렵게 고치지 말고, 한국어 학습자가 이해할 수 있는 쉬운 설명을 쓰며, 문법 오류만 지적하지 말고 연어가 담화 구성에 어떻게 기여하는지 반드시 설명하라.

반드시 아래 JSON 객체만 출력하라(마크다운/코드펜스/설명 없이):
{
  "score": 0부터 100 사이 정수,
  "used": ["학습자가 실제로 사용한 연어 목록"],
  "good": ["잘한 점 2~3개"],
  "improve": ["보완할 점 1~2개"],
  "cohesion": "연어가 문장과 문장을 어떻게 연결했는지 쉬운 한 문단 설명",
  "revision": "학습자 문장을 더 자연스러운 구어체 또는 가사체로 다듬은 수정 예시"
}`;
}

/* 템플릿(오프라인) 채점: API 실패 시 사용 */
function templateGrade({ required, learnerText }) {
  const used = (required || []).filter((w) => learnerText.includes(w.split(" ")[0]) || learnerText.includes(w));
  const hit = used.length > 0;
  return {
    score: hit ? 82 : 68,
    used: used.length ? used : ["(자동 인식 실패)"],
    good: [
      hit ? "제시된 연어를 문장 안에서 사용하려는 시도가 잘 나타났습니다." : "상황에 반응하는 발화를 만들었습니다.",
      "생각을 문장으로 표현하려는 흐름이 보입니다.",
    ],
    improve: [hit ? "연어 앞뒤 문장을 한 번 더 이어 주면 담화 응집성이 높아집니다." : "제시된 연어를 직접 넣어 보면 더 자연스러워집니다."],
    cohesion: "연어는 감정·관계·상황 변화를 이어 주는 다리 역할을 합니다. 앞 문장의 상황과 연어를 연결하면 발화가 하나의 이야기처럼 자연스럽게 이어집니다.",
    revision: learnerText.trim() || "(작성한 문장이 여기에 다듬어져 표시됩니다.)",
  };
}

