/* =============================== 활동 1: 드래그앤드롭 빈칸 채우기 (§4) =============================== */
function DragFillScreen({ go, award }) {
  const [idx, setIdx] = useState(0);
  const [placed, setPlaced] = useState(null);
  const [result, setResult] = useState(null);
  const [correctCount, setCorrectCount] = useState(0);
  const q = DRAG_FILL[idx];
  const last = idx === DRAG_FILL.length - 1;

  /* ---- 드래그 상태 ---- */
  const [dragging, setDragging] = useState(null);
  const [dragPos, setDragPos] = useState({ x: 0, y: 0 });
  const blankRef = React.useRef(null);
  const draggingRef = React.useRef(null);

  // pointerdown: 드래그 시작
  function handlePointerDown(opt, e) {
    if (result) return;
    e.preventDefault();
    draggingRef.current = opt;
    setDragging(opt);
    setDragPos({ x: e.clientX, y: e.clientY });
  }

  // 전역 pointermove / pointerup: window 레벨에서 등록 (React 합성 이벤트 우회)
  useEffect(() => {
    if (!dragging) return;
    function onMove(e) {
      e.preventDefault();
      setDragPos({ x: e.clientX, y: e.clientY });
    }
    function onUp(e) {
      const current = draggingRef.current;
      if (current && blankRef.current) {
        const rect = blankRef.current.getBoundingClientRect();
        const hit = e.clientX >= rect.left && e.clientX <= rect.right && e.clientY >= rect.top && e.clientY <= rect.bottom;
        if (hit) setPlaced(current);
      }
      draggingRef.current = null;
      setDragging(null);
    }
    window.addEventListener("pointermove", onMove, { passive: false });
    window.addEventListener("pointerup", onUp);
    window.addEventListener("pointercancel", onUp);
    return () => {
      window.removeEventListener("pointermove", onMove);
      window.removeEventListener("pointerup", onUp);
      window.removeEventListener("pointercancel", onUp);
    };
  }, [dragging]);

  function check() {
    if (!placed) return;
    const ok = placed === q.answer;
    setResult(ok ? "ok" : "no");
    playSound(ok ? "correct" : "wrong");
    if (ok) { award(SCORE_RULES.drag, "drag"); setCorrectCount((c) => c + 1); }
  }
  function next() {
    if (last) { go("course"); return; }
    setIdx((i) => i + 1); setPlaced(null); setResult(null);
  }
  function reset() {
    if (result) return;
    setPlaced(null);
  }

  return (
    <div className="px-5 pt-3 pb-24" style={{ touchAction: dragging ? "none" : "auto" }}>
      <Header title="빈칸 채우기 🧩" onBack={() => go("course")} />
      <p className="text-center tt11 text-purple-600 mb-1">알맞은 연어를 골라 빈칸에 넣으세요 ({idx + 1}/{DRAG_FILL.length})</p>
      <p className="text-center tt10 text-pink-400 mb-2">💡 보기를 끌어서 빈칸에 놓으세요</p>

      <div className="rounded-2xl glass85 shadow p-3">
        <Pill className="bg-purple-100 text-purple-500 mb-2">상황 · {q.situation}</Pill>
        <p className="tt13 text-purple-800 leading-relaxed mt-1">
          {q.before}
          <span ref={blankRef}
            onClick={reset}
            className={`inline-flex items-center justify-center min-w-[88px] px-2 py-0.5 mx-0.5 rounded-lg align-middle border-2 border-dashed transition-all cursor-pointer ${
              dragging && !placed ? "border-pink-400 bg-pink-100 scale-110 shadow-md" :
              placed ? (result === "ok" ? "border-emerald-300 bg-emerald-50 text-emerald-600" : result === "no" ? "border-rose-300 bg-rose-50 text-rose-500" : "border-pink-300 bg-pink-50 text-pink-600") : "border-purple-300 bg-white/60 text-purple-300"
            }`}>
            {placed || "____"}
          </span>
          {q.after}
        </p>
        {placed && !result && <p className="tt10 text-purple-400 mt-2">💡 빈칸을 탭하면 다시 선택할 수 있어요</p>}
      </div>

      {/* 선택지 칩 */}
      <div className="grid grid-cols-2 gap-2 mt-3">
        {q.options.map((opt, i) => {
          const used = placed === opt;
          const isDragging = dragging === opt;
          return (
            <button key={opt}
              onPointerDown={(e) => handlePointerDown(opt, e)}
              className={`rounded-xl py-3 px-3 tt12 font-bold shadow-sm transition select-none touch-none flex items-center gap-2 ${
                isDragging ? "opacity-30 scale-95" :
                used ? "bg-gradient-to-r from-purple-400 to-pink-400 text-white" : "glass85 text-purple-700 active:scale-95"
              }`}
              style={{ touchAction: "none" }}>
              <span className={`text-xs font-black shrink-0 w-4 text-left ${used || isDragging ? "text-white/60" : "text-pink-400"}`}>{i + 1}</span>
              <span>{opt}</span>
            </button>
          );
        })}
      </div>

      {/* 드래그 중 고스트 */}
      {dragging && (
        <div className="fixed pointer-events-none z-50 rounded-xl px-4 py-2 text-sm font-black bg-gradient-to-r from-purple-500 to-pink-500 text-white shadow-xl"
          style={{ left: dragPos.x, top: dragPos.y, transform: "translate(-50%, -50%) rotate(-3deg)" }}>
          {dragging}
        </div>
      )}

      {!result ? (
        <button onClick={check} disabled={!placed}
          className="w-full mt-3 rounded-full py-2.5 text-sm font-black bg-gradient-to-r from-purple-400 to-pink-400 text-white shadow active:scale-95 disabled:opacity-50">
          정답 확인
        </button>
      ) : (
        <div className="mt-3 space-y-2">
          <div className={`rounded-2xl p-3 shadow ${result === "ok" ? "bg-emerald-50" : "bg-rose-50"}`}>
            <div className={`text-sm font-black ${result === "ok" ? "text-emerald-600" : "text-rose-500"}`}>
              {result === "ok" ? "정답입니다! 🎉" : "조금 아쉬워요"}
            </div>
            <p className="tt12 text-purple-700 mt-1 leading-relaxed">{result === "ok" ? q.explainOk : q.explainNo}</p>
            {result === "no" && <div className="tt11 text-purple-500 mt-1">정답: <b className="text-pink-600">{q.answer}</b></div>}
          </div>
          <button onClick={next}
            className="w-full rounded-full py-2.5 text-sm font-black bg-pink-400 text-white shadow active:scale-95">
            {last ? "코스로 돌아가기" : "다음 문제 →"}
          </button>
        </div>
      )}

      <div className="tt10 text-purple-500 text-left mt-2">맞힌 문제 {correctCount}개 {correctCount >= 3 && "· 🧩 연어 조합왕 달성!"}</div>
    </div>
  );
}

/* =============================== 활동 2: 연어 조각 맞추기 퍼즐 (§5) =============================== */
function PuzzleScreen({ go, progress, award }) {
  const [page, setPage] = useState(0);           // 0 or 1
  const [pickId, setPickId] = useState(null);
  const [matched, setMatched] = useState({});     // { [pairId]: true }
  const [wrong, setWrong] = useState(null);
  const [shaking, setShaking] = useState(false);
  const alreadyDone = !!progress.done.puzzle;

  const currentPairs = PUZZLE.pages[page];
  const allMatched = Object.keys(matched).length === PUZZLE.pairs.length;
  const pageMatched = currentPairs.filter((p) => matched[p.id]).length;
  const pageAllDone = pageMatched === currentPairs.length;

  // 페이지별 우측 셔플 (페이지 변경 시 재셔플)
  const rightShuffled = React.useMemo(() => {
    const arr = [...currentPairs];
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
  }, [page]);

  const [noLeftWarn, setNoLeftWarn] = useState(false);
  const [leftHighlight, setLeftHighlight] = useState(false);

  function tapRight(rp) {
    if (!pickId) {
      playSound("zap");
      setShaking(true); setNoLeftWarn(true); setLeftHighlight(true);
      setTimeout(() => { setShaking(false); setNoLeftWarn(false); setLeftHighlight(false); }, 800);
      return;
    }
    if (rp.id === pickId) {
      const nm = { ...matched, [pickId]: true };
      setMatched(nm); setPickId(null); setWrong(null);
      playSound("correct");
      if (Object.keys(nm).length === PUZZLE.pairs.length && !alreadyDone) award(SCORE_RULES.puzzle, "puzzle");
    } else {
      setWrong(rp.id); setShaking(true); playSound("buzz");
      setTimeout(() => { setWrong(null); setShaking(false); }, 600);
    }
  }

  const pickedPair = pickId ? currentPairs.find((p) => p.id === pickId) : null;

  return (
    <div className="px-5 pt-3 pb-24">
      <Header title="연어 퍼즐 🎯" onBack={() => go("course")} />

      {/* 페이지 탭 */}
      <div className="flex gap-2 mb-2">
        {PUZZLE.pages.map((pg, i) => {
          const pgMatched = pg.filter((p) => matched[p.id]).length;
          const pgDone = pgMatched === pg.length;
          return (
            <button key={i} onClick={() => { setPage(i); setPickId(null); }}
              className={`flex-1 rounded-full py-1.5 tt11 font-bold transition ${page === i ? "bg-gradient-to-r from-purple-400 to-pink-400 text-white shadow" : "glass85 text-purple-600 active:scale-95"}`}>
              {pgDone ? "✓ " : ""}{["A set", "B set"][i]} ({pgMatched}/{pg.length})
            </button>
          );
        })}
      </div>

      <p className="text-center tt10 text-purple-500 mb-1">왼쪽을 누른 뒤 어울리는 오른쪽 조각을 연결하세요</p>
      <p className="text-center tt10 text-pink-400 mb-2">💡 같은 어절이 여러 번 나와요 — 의미 힌트를 확인하세요</p>

      <div className={"flex gap-2" + (shaking ? " kf-shake" : "")}>
        {/* 왼쪽 */}
        <div className="flex-1 space-y-1.5">
          {currentPairs.map((p) => {
            const done = !!matched[p.id];
            const picked = pickId === p.id;
            return (
              <button key={p.id} disabled={done} onClick={() => setPickId(p.id)}
                className={`w-full rounded-xl py-2 px-2 shadow-sm transition text-left ${
                  done ? "bg-emerald-100 text-emerald-600"
                  : picked ? "bg-gradient-to-r from-purple-400 to-pink-400 text-white ring-2 ring-pink-300"
                  : leftHighlight ? "bg-amber-100 text-amber-700 ring-2 ring-amber-400 scale-105"
                  : "glass85 text-purple-700 active:scale-95"
                }`}>
                <div className="tt12 font-bold">{done ? `${p.left} → ${p.right} ✓` : p.left}</div>
                {!done && <div className={`tt9 font-normal mt-0.5 ${picked ? "text-white/80" : leftHighlight ? "text-amber-500" : "text-purple-400"}`}>{p.hint}</div>}
              </button>
            );
          })}
        </div>
        {/* 오른쪽 */}
        <div className="flex-1 space-y-1.5">
          {rightShuffled.map((rp) => {
            const used = !!matched[rp.id];
            const isWrong = wrong === rp.id;
            return (
              <button key={rp.id} disabled={used} onClick={() => tapRight(rp)}
                className={`w-full rounded-xl py-2 px-2 tt12 font-bold shadow-sm transition ${
                  used ? "bg-emerald-50 text-emerald-300" : isWrong ? "bg-rose-200 text-rose-600 ring-2 ring-rose-400" : "glass85 text-pink-600 active:scale-95"
                }`}
                style={{ minHeight: "3rem" }}>
                {rp.right}
              </button>
            );
          })}
        </div>
      </div>

      {pickedPair && !shaking && (
        <div className="tt11 text-purple-500 text-center mt-2">
          「{pickedPair.left}」<span className="text-purple-400">({pickedPair.hint})</span> — 어울리는 오른쪽을 누르세요
        </div>
      )}
      {shaking && noLeftWarn && (
        <div className="tt11 text-orange-500 text-center mt-2 font-bold animate-pulse">
          ⚡ 왼쪽 조각을 먼저 클릭하세요!
        </div>
      )}
      {shaking && !noLeftWarn && (
        <div className="tt11 text-rose-500 text-center mt-2 font-bold">❌ 다시 시도해 보세요!</div>
      )}

      {/* A set 완료 → B set 이동 버튼 */}
      {pageAllDone && page === 0 && !allMatched && (
        <button onClick={() => { setPage(1); setPickId(null); }}
          className="w-full mt-3 rounded-full py-2.5 text-sm font-black bg-gradient-to-r from-purple-400 to-pink-400 text-white shadow active:scale-95">
          B set으로 →
        </button>
      )}

      {/* 전체 완료 */}
      {allMatched && (
        <div className="mt-3 rounded-2xl bg-emerald-50 p-3 shadow text-center">
          <div className="text-sm font-black text-emerald-600">🎉 연어 {PUZZLE.pairs.length}개 전부 완성!</div>
          <p className="tt10 text-purple-600 mt-1 leading-relaxed">
            {PUZZLE.pairs.map((p) => `${p.left} ${p.right}`).join(" · ")}
          </p>
          <button onClick={() => go("course")} className="mt-2 rounded-full px-5 py-2 tt12 font-black bg-pink-400 text-white active:scale-95">
            코스로 돌아가기
          </button>
        </div>
      )}
    </div>
  );
}

