/* =============================== 활동 5: 연어로 K-POP 가사 만들기 (§8) =============================== */
const LYRIC_TASKS = [
  { situation: "오랜 친구와 멀어졌지만 다시 만나고 싶은 마음을 담은 가사를 만들어 보세요.", required: ["눈물이 나다", "마음이 아프다"], hint: "예)\n네가 없는 밤마다 마음이 아파\n그때 생각하면 아직도 눈물이 나" },
  { situation: "힘든 시기를 함께 이겨 내자는 응원의 가사를 만들어 보세요.", required: ["손을 잡다", "힘을 내다"], hint: "예)\n지금 네 손을 잡을게\n다시 한번 힘을 내 봐\n우리 함께라면 괜찮아" },
  { situation: "이루고 싶은 꿈을 향해 나아가는 청춘의 가사를 만들어 보세요.", required: ["꿈을 꾸다", "길을 잃다"], hint: "예)\n때론 길을 잃어도\n포기하지 않을 거야\n더 큰 꿈을 꾸며 달려갈 테니까" },
];
