/* ── QUESTION_ITEMS 지연 산출 (QUESTION_BANK 정의 완료 후) ── */
QUESTION_ITEMS = QUESTION_BANK.map(function(q) {
  var matchedExpr = COLLOCATIONS.find(function(c) { return c.expression === q.expression; });
  return {
    questionId: q.id,
    expressionId: matchedExpr ? ("expr_" + String(matchedExpr.id).padStart(3, "0")) : null,
    songId: null,
    questionType: "fill_in_blank",
    prompt: q.situation || "",
    options: q.options || [],
    answer: q.answer || "",
    difficulty: q.difficulty || "중",
    firstWrongFeedback: q.firstWrongFeedback || "",
    finalExplanation: q.finalExplanation || "",
  };
});

