/* =============================== 상황 허브 =============================== */
function SituationHubScreen({ go, ctx }) {
  const sit = SITUATIONS.find((s) => s.id === ctx.situation);
  if (!sit) return <div className="p-5">상황 정보를 찾을 수 없습니다.</div>;
  const desc = SIT_DESC[sit.id] || "이 상황의 의미장(意味場)에 속하는 연어를 학습합니다.";
  const songCount = SONGS.filter((x) => x.situation === sit.id).length;
  const coreCount = (SIT_CORE[sit.id] || []).length;
  const findCount = (SIT_DIALOGUE[sit.id] || []).length;
  const speakCount = (SIT_SPEAK[sit.id] || []).length;
  const lyricCount = (SIT_LYRIC[sit.id] || []).length;
  const counts = { songs: songCount, core: coreCount, find: findCount, speak: speakCount, lyric: lyricCount };

  return (
    <div className="px-5 pt-3 pb-24">
      <Header title={sit.name} onBack={() => go("situations")} />
      <div className={`rounded-2xl p-4 mt-2 bg-gradient-to-br ${sit.grad} text-white shadow`}>
        <div className="text-3xl">{sit.icon}</div>
        <div className="text-lg font-black mt-1">{sit.name}</div>
        <div className="tt11 opacity-90">{sit.sub}</div>
        <p className="tt12 mt-2 leading-relaxed bg-white/25 rounded-xl p-2">{desc}</p>
      </div>

      <SectionTitle note="순서대로 진행을 권장">이 상황의 활동</SectionTitle>
      <div className="space-y-2">
        {SIT_TABS.map((t) => {
          const cnt = counts[t.id];
          const disabled = cnt === 0;
          return (
            <button key={t.id} disabled={disabled}
              onClick={() => go("sitActivity", { situation: sit.id, tab: t.id })}
              className={`w-full rounded-2xl p-3 glass85 shadow flex items-center gap-3 transition text-left ${disabled ? "opacity-40" : "active:scale-95"}`}>
              <div className="w-11 h-11 rounded-xl flex items-center justify-center text-xl shrink-0 bg-gradient-to-br from-purple-200 to-pink-200">{t.icon}</div>
              <div className="flex-1 min-w-0">
                <div className="text-sm font-bold text-purple-700">{t.label}</div>
                <div className="tt10 text-purple-600">{disabled ? "준비 중" : `${cnt}개 콘텐츠`}</div>
              </div>
              <span className="text-purple-500">→</span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

/* =============================== 상황 활동 라우터 =============================== */
function SituationActivityScreen({ go, ctx, award, saveRecord, l1Lang }) {
  const sit = SITUATIONS.find((s) => s.id === ctx.situation);
  if (!sit) return <div className="p-5">상황 정보를 찾을 수 없습니다.</div>;
  const tab = ctx.tab || "songs";
  const tabMeta = SIT_TABS.find((t) => t.id === tab) || SIT_TABS[0];

  const TabBar = () => (
    <div className="flex flex-wrap gap-1.5 mt-2">
      {SIT_TABS.map((t) => {
        const active = t.id === tab;
        return (
          <button key={t.id}
            onClick={() => go("sitActivity", { situation: sit.id, tab: t.id })}
            className={`rounded-full px-3 py-1.5 tt11 font-bold transition ${active ? "bg-gradient-to-r from-purple-400 to-pink-400 text-white shadow" : "glass85 text-purple-600 active:scale-95"}`}>
            {t.icon} {t.label}
          </button>
        );
      })}
    </div>
  );

  let body;
  switch (tab) {
    case "songs": body = <SitSongs sit={sit} go={go} />; break;
    case "core":  body = <SitCorePhrases sit={sit} go={go} l1Lang={l1Lang} />; break;
    case "find":  body = <SitDialogueFind sit={sit} />; break;
    case "speak": body = <SitSpeakMission sit={sit} />; break;
    case "lyric": body = <SitLyricMake sit={sit} saveRecord={saveRecord} />; break;
    default:      body = <SitSongs sit={sit} go={go} />;
  }

  return (
    <div className="px-5 pt-3 pb-24">
      <Header title={`${sit.name} · ${tabMeta.label}`} onBack={() => go("sitHub", { situation: sit.id })} />
      <TabBar />
      <div className="mt-3">{body}</div>
    </div>
  );
}

